<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { width: 100%; height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", "Noto Sans", sans-serif;
    background: #2c001e;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(ellipse at 20% 25%, rgba(233,84,32,0.35) 0%, rgba(233,84,32,0) 55%),
      radial-gradient(ellipse at 80% 75%, rgba(119,33,111,0.55) 0%, rgba(119,33,111,0) 60%),
      linear-gradient(135deg, #4b1141 0%, #2c001e 55%, #1a0b14 100%);
    overflow: hidden;
  }

  /* ---------- Top bar ---------- */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 30px;
    background: rgba(20, 10, 18, 0.92);
    color: #eee;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    font-size: 13px;
    z-index: 5000;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #topbar .tb-left { font-weight: 700; letter-spacing: .3px; }
  #topbar .tb-right { display: flex; gap: 10px; opacity: .85; }

  /* ---------- Taskbar / dock ---------- */
  #taskbar {
    position: absolute;
    left: 8px;
    top: 50%;
    transform: translateY(-50%);
    width: 68px;
    background: rgba(20, 10, 18, 0.82);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 16px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 10px;
    padding: 12px 0;
    z-index: 4000;
    backdrop-filter: blur(6px);
  }
  #taskbar button {
    width: 52px;
    height: 52px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    background: rgba(255,255,255,0.06);
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background .15s, transform .1s;
    padding: 0;
  }
  #taskbar button:hover { background: rgba(255,255,255,0.16); transform: scale(1.06); }
  #taskbar button:active { transform: scale(.97); }
  #taskbar button svg { width: 34px; height: 34px; display: block; }
  #taskbar .dock-sep {
    width: 40px; height: 1px;
    background: rgba(255,255,255,0.15);
  }

  /* ---------- Windows ---------- */
  .app-window {
    position: absolute;
    width: 640px;
    height: 440px;
    min-width: 360px;
    min-height: 240px;
    background: #2e2a32;
    border: 1px solid rgba(0,0,0,0.6);
    border-radius: 10px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55), 0 2px 8px rgba(0,0,0,0.4);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .app-window.hidden { display: none; }

  .titlebar {
    height: 38px;
    flex: 0 0 38px;
    background: linear-gradient(#3a353f, #322d37);
    border-bottom: 1px solid #221e26;
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: move;
    gap: 8px;
  }
  .titlebar .win-title {
    flex: 1;
    text-align: center;
    color: #ddd;
    font-size: 13px;
    font-weight: 700;
    letter-spacing: .2px;
    pointer-events: none;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
  }
  .win-close {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    border: none;
    background: #e95420;
    color: #fff;
    font-size: 13px;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 0 0 22px;
    transition: filter .12s;
  }
  .win-close:hover { filter: brightness(1.2); }

  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    background: #262229;
  }

  /* ---------- Files app ---------- */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #322d37;
    border-bottom: 1px solid #1d1a20;
    flex: 0 0 auto;
  }
  #files-up {
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.07);
    color: #ddd;
    border-radius: 6px;
    padding: 5px 12px;
    font-size: 14px;
    cursor: pointer;
    transition: background .12s;
  }
  #files-up:hover:not(:disabled) { background: rgba(255,255,255,0.16); }
  #files-up:disabled { opacity: .35; cursor: default; }
  #files-path {
    flex: 1;
    background: #1d1a20;
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 6px;
    color: #e8e6ea;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 13px;
    padding: 6px 10px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }
  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(92px, 1fr));
    gap: 6px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 10px 4px;
    border-radius: 8px;
    color: #e8e6ea;
    font-size: 12px;
    cursor: default;
    text-align: center;
    word-break: break-all;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(233,84,32,0.35); }
  .fs-item .fs-icon { width: 40px; height: 40px; pointer-events: none; }
  .fs-item .fs-name { pointer-events: none; line-height: 1.25; }
  .fs-empty {
    grid-column: 1 / -1;
    color: #888;
    font-size: 13px;
    text-align: center;
    padding: 30px 0;
  }

  /* ---------- Notepad app ---------- */
  #notepad-toolbar {
    display: flex;
    align-items: stretch;
    background: #322d37;
    border-bottom: 1px solid #1d1a20;
    flex: 0 0 auto;
  }
  #tabs {
    flex: 1;
    display: flex;
    overflow-x: auto;
    min-width: 0;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 12px;
    font-size: 12.5px;
    color: #bbb;
    background: transparent;
    border-right: 1px solid #26222b;
    cursor: pointer;
    white-space: nowrap;
    max-width: 180px;
  }
  .tab:hover { background: rgba(255,255,255,0.06); }
  .tab.active {
    background: #262229;
    color: #fff;
    box-shadow: inset 0 -2px 0 #e95420;
  }
  .tab .tab-label {
    overflow: hidden;
    text-overflow: ellipsis;
    pointer-events: none;
  }
  .tab .tab-x {
    border: none;
    background: transparent;
    color: #999;
    font-size: 12px;
    line-height: 1;
    cursor: pointer;
    padding: 2px 4px;
    border-radius: 4px;
  }
  .tab .tab-x:hover { background: rgba(255,255,255,0.15); color: #fff; }
  #new-tab {
    flex: 0 0 auto;
    border: none;
    background: transparent;
    color: #ccc;
    font-size: 18px;
    padding: 0 14px;
    cursor: pointer;
  }
  #new-tab:hover { background: rgba(255,255,255,0.1); color: #fff; }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #262229;
    color: #eceaee;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 14px;
    line-height: 1.5;
    padding: 12px 14px;
    min-height: 0;
    user-select: text;
  }

  ::-webkit-scrollbar { width: 10px; height: 10px; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.18); border-radius: 5px; }
  ::-webkit-scrollbar-track { background: transparent; }
</style>
</head>
<body>
<div id="desktop">

  <div id="topbar">
    <span class="tb-left">Activities</span>
    <span class="tb-center" id="clock">--:--</span>
    <span class="tb-right"><span>&#9662; en</span><span>&#128266;</span><span>&#128267; 100%</span></span>
  </div>

  <div id="taskbar">
    <button id="open-files" title="Files" aria-label="Open Files">
      <svg viewBox="0 0 48 48"><path fill="#f5a623" d="M6 10c0-2.2 1.8-4 4-4h10l4 5h14c2.2 0 4 1.8 4 4v21c0 2.2-1.8 4-4 4H10c-2.2 0-4-1.8-4-4V10z"/><path fill="#ffc966" d="M6 17h36v19c0 2.2-1.8 4-4 4H10c-2.2 0-4-1.8-4-4V17z"/></svg>
    </button>
    <button id="open-notepad" title="Notepad" aria-label="Open Notepad">
      <svg viewBox="0 0 48 48"><rect x="9" y="5" width="30" height="38" rx="3" fill="#ececec"/><rect x="9" y="5" width="30" height="8" rx="3" fill="#e95420"/><rect x="14" y="19" width="20" height="2.5" rx="1.2" fill="#9a9a9a"/><rect x="14" y="25" width="20" height="2.5" rx="1.2" fill="#9a9a9a"/><rect x="14" y="31" width="13" height="2.5" rx="1.2" fill="#9a9a9a"/></svg>
    </button>
    <div class="dock-sep"></div>
    <button title="Ubuntu" aria-label="Ubuntu" onclick="void 0">
      <svg viewBox="0 0 48 48"><circle cx="24" cy="24" r="20" fill="#e95420"/><circle cx="24" cy="24" r="8" fill="none" stroke="#fff" stroke-width="3"/><circle cx="24" cy="9.5" r="3.4" fill="#fff"/><circle cx="11.5" cy="31.5" r="3.4" fill="#fff"/><circle cx="36.5" cy="31.5" r="3.4" fill="#fff"/></svg>
    </button>
  </div>

  <!-- ============ Files window ============ -->
  <div id="files-window" class="app-window hidden" style="left: 120px; top: 80px;">
    <div class="titlebar">
      <span class="win-title">&#128193; Files</span>
      <button class="win-close" title="Close">&#10005;</button>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up" title="Up one level">&#8593; Up</button>
