</div>

<script>
(function () {
  "use strict";

  /* ================= Clock ================= */
  var clock = document.getElementById("clock");
  function tick() {
    var d = new Date();
    var days = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
    var months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    var h = String(d.getHours()).padStart(2, "0");
    var m = String(d.getMinutes()).padStart(2, "0");
    clock.textContent = days[d.getDay()] + " " + months[d.getMonth()] + " " + d.getDate() + "  " + h + ":" + m;
  }
  tick();
  setInterval(tick, 10000);

  /* ================= Window management ================= */
  var zTop = 200;
  function bringToFront(win) {
    zTop += 1;
    win.style.zIndex = zTop;
  }

  function setupWindow(winId, launcherId) {
    var win = document.getElementById(winId);
    var launcher = document.getElementById(launcherId);
    var titlebar = win.querySelector(".titlebar");
    var closeBtn = win.querySelector(".win-close");

    launcher.addEventListener("click", function () {
      win.classList.remove("hidden");
      bringToFront(win);
      clampIntoView(win);
    });

    closeBtn.addEventListener("click", function (e) {
      e.stopPropagation();
      win.classList.add("hidden");
    });

    win.addEventListener("mousedown", function () { bringToFront(win); });

    /* dragging */
    var dragging = false, offX = 0, offY = 0;
    titlebar.addEventListener("mousedown", function (e) {
      if (e.target === closeBtn) return;
      dragging = true;
      var r = win.getBoundingClientRect();
      offX = e.clientX - r.left;
      offY = e.clientY - r.top;
      bringToFront(win);
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      var x = e.clientX - offX;
      var y = e.clientY - offY;
      x = Math.max(-win.offsetWidth + 80, Math.min(x, window.innerWidth - 80));
      y = Math.max(30, Math.min(y, window.innerHeight - 40));
      win.style.left = x + "px";
      win.style.top = y + "px";
    });
    document.addEventListener("mouseup", function () { dragging = false; });
    return win;
  }

  function clampIntoView(win) {
    var r = win.getBoundingClientRect();
    if (r.right > window.innerWidth) win.style.left = Math.max(90, window.innerWidth - r.width - 10) + "px";
    if (r.bottom > window.innerHeight) win.style.top = Math.max(32, window.innerHeight - r.height - 10) + "px";
  }

  setupWindow("files-window", "open-files");
  setupWindow("notepad-window", "open-notepad");

  /* ================= Files app ================= */
  // Fake filesystem: objects = directories, strings = files.
  var FS = {
    "bin": { "bash": "f", "cat": "f", "cp": "f", "ls": "f", "mv": "f", "rm": "f", "sh": "f" },
    "boot": { "grub": { "grub.cfg": "f" }, "vmlinuz": "f", "initrd.img": "f" },
    "dev": { "null": "f", "random": "f", "sda": "f", "tty0": "f" },
    "etc": {
      "apt": { "sources.list": "f" },
      "ssh": { "sshd_config": "f" },
      "fstab": "f", "hostname": "f", "hosts": "f", "os-release": "f", "passwd": "f"
    },
    "home": {
      "user": {
        "Documents": { "notes.txt": "f", "resume.pdf": "f", "todo.md": "f" },
        "Downloads": { "ubuntu-24.04.iso": "f", "wallpaper.png": "f" },
        "Pictures": { "screenshot.png": "f", "vacation.jpg": "f" },
        "Music": {},
        "Videos": {},
        ".bashrc": "f",
        ".profile": "f"
      }
    },
    "lib": { "modules": {}, "systemd": {} },
    "opt": {},
    "proc": { "cpuinfo": "f", "meminfo": "f", "uptime": "f" },
    "root": {},
    "tmp": {},
    "usr": {
      "bin": { "python3": "f", "gcc": "f", "vim": "f", "curl": "f" },
      "lib": {},
      "local": { "bin": {} },
      "share": { "doc": {}, "icons": {}, "themes": {} }
    },
    "var": {
      "log": { "syslog": "f", "auth.log": "f", "kern.log": "f" },
      "cache": {},
      "tmp": {},
      "www": { "html": { "index.html": "f" } }
    }
  };

  var cwd = []; // path segments; [] = root
  var filesPath = document.getElementById("files-path");
  var filesList = document.getElementById("files-list");
  var filesUp = document.getElementById("files-up");

  function dirAt(segments) {
    var node = FS;
    for (var i = 0; i < segments.length; i++) {
      node = node[segments[i]];
      if (typeof node !== "object" || node === null) return null;
    }
    return node;
  }

  function folderIcon() {
    return '<svg class="fs-icon" viewBox="0 0 48 48"><path fill="#f5a623" d="M6 10c0-2.2 1.8-4 4-4h10l4 5h14c2.2 0 4 1.8 4 4v21c0 2.2-1.8 4-4 4H10c-2.2 0-4-1.8-4-4V10z"/><path fill="#ffc966" d="M6 17h36v19c0 2.2-1.8 4-4 4H10c-2.2 0-4-1.8-4-4V17z"/></svg>';
  }
  function fileIcon() {
    return '<svg class="fs-icon" viewBox="0 0 48 48"><path fill="#dcdcdc" d="M12 4h16l10 10v30H12z"/><path fill="#b8b8b8" d="M28 4l10 10H28z"/><rect x="17" y="22" width="14" height="2" rx="1" fill="#8a8a8a"/><rect x="17" y="27" width="14" height="2" rx="1" fill="#8a8a8a"/><rect x="17" y="32" width="9" height="2" rx="1" fill="#8a8a8a"/></svg>';
  }

  function renderFiles() {
    var path = "/" + cwd.join("/");
    filesPath.textContent = cwd.length ? path : "/";
    filesUp.disabled = cwd.length === 0;
    filesList.innerHTML = "";

    var dir = dirAt(cwd);
    if (!dir) { cwd = []; renderFiles(); return; }

    var names = Object.keys(dir).sort(function (a, b) {
      var aDir = typeof dir[a] === "object", bDir = typeof dir[b] === "object";
      if (aDir !== bDir) return aDir ? -1 : 1;
      return a.localeCompare(b);
    });

    if (names.length === 0) {
      var empty = document.createElement("div");
      empty.className = "fs-empty";
      empty.textContent = "This folder is empty";
      filesList.appendChild(empty);
      return;
    }

    names.forEach(function (name) {
      var isDir = typeof dir[name] === "object";
      var el = document.createElement("div");
      el.className = "fs-item";
      el.innerHTML = (isDir ? folderIcon() : fileIcon()) +
        '<span class="fs-name"></span>';
      el.querySelector(".fs-name").textContent = name;
      el.title = name;

      el.addEventListener("click", function () {
        filesList.querySelectorAll(".fs-item.selected").forEach(function (s) {
          s.classList.remove("selected");
        });
        el.classList.add("selected");
      });

      if (isDir) {
        el.addEventListener("dblclick", function () {
          cwd.push(name);
          renderFiles();
        });
      }
      filesList.appendChild(el);
    });
  }

  filesUp.addEventListener("click", function () {
    if (cwd.length > 0) {
      cwd.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ================= Notepad app ================= */
  var STORE_KEY = "ubuntu-notepad-tabs-v1";
  var tabsEl = document.getElementById("tabs");
  var newTabBtn = document.getElementById("new-tab");
  var editor = document.getElementById("editor");

  var state = loadState();

  function loadState() {
    try {
      var raw = localStorage.getItem(STORE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          if (typeof parsed.active !== "number" ||
              parsed.active < 0 || parsed.active >= parsed.tabs.length) {
            parsed.active = 0;
          }
          parsed.tabs = parsed.tabs.map(function (t, i) {
            return {
              title: typeof t.title === "string" && t.title ? t.title : ("Untitled " + (i + 1)),
              content: typeof t.content === "string" ? t.content : ""
            };
          });
          return parsed;
        }
      }
    } catch (e) { /* corrupted storage — start fresh */ }
    return {
      tabs: [{ title: "Untitled 1", content: "" }],
      active: 0,
      counter: 1
    };
  }

  function saveState() {
    try {
      localStorage.setItem(STORE_KEY, JSON.stringify(state));
    } catch (e) { /* storage full or unavailable */ }
  }

  function renderTabs() {
    tabsEl.innerHTML = "";
    state.tabs.forEach(function (tab, i) {
      var t = document.createElement("div");
      t.className = "tab" + (i === state.active ? " active" : "");
      var label = document.createElement("span");
      label.className = "tab-label";
      label.textContent = tab.title;
      t.appendChild(label);

      if (state.tabs.length > 1) {
        var x = document.createElement("button");
        x.className = "tab-x";
        x.title = "Close tab";
        x.textContent = "\u2715";
        x.addEventListener("click", function (e) {
          e.stopPropagation();
          closeTab(i);
        });
        t.appendChild(x);
      }

      t.addEventListener("click", function () {
        state.active = i;
        saveState();
        renderTabs();
        renderEditor();
      });
      tabsEl.appendChild(t);
    });
  }

  function renderEditor() {
    editor.value = state.tabs[state.active].content;
  }

  function closeTab(i) {
    state.tabs.splice(i, 1);
    if (state.active >= state.tabs.length) state.active = state.tabs.length - 1;
    else if (i < state.active) state.active -= 1;
    saveState();
    renderTabs();
    renderEditor();
  }

  newTabBtn.addEventListener("click", function () {
    state.counter = (state.counter || state.tabs.length) + 1;
    state.tabs.push({ title: "Untitled " + state.counter, content: "" });
    state.active = state.tabs.length - 1;
    saveState();
    renderTabs();
    renderEditor();
    editor.focus();
  });

  editor.addEventListener("input", function () {
    state.tabs[state.active].content = editor.value;
    saveState();
  });

  renderTabs();
  renderEditor();
})();
</script>
</body>
</html>
